insert into bank_questions (question_key, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('5-4-break-even:tf:9eddbc05', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "If a business sells more than its break-even output, it will make a profit."}'::jsonb, '{"answer": true, "explain": "TRUE. Once output exceeds break-even, every additional unit sold generates profit — because total revenue now exceeds total costs."}'::jsonb),
('5-4-break-even:tf:8de7fb35', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Fixed costs change depending on the level of output produced."}'::jsonb, '{"answer": false, "explain": "FALSE. Fixed costs remain the same regardless of output. Rent is the same whether a business produces 100 or 10,000 units. It is variable costs that change with output."}'::jsonb),
('5-4-break-even:tf:e7f6cefe', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "An increase in selling price will cause the break-even output to decrease."}'::jsonb, '{"answer": true, "explain": "TRUE. A higher price increases the contribution per unit. Since break-even = FC ÷ contribution, a larger contribution means fewer units need to be sold to cover fixed costs."}'::jsonb),
('5-4-break-even:tf:a45d3df6', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "An increase in variable costs per unit will cause the break-even output to decrease."}'::jsonb, '{"answer": false, "explain": "FALSE. If variable costs increase, contribution per unit falls (price − VC is smaller). A lower contribution means MORE units must be sold to cover fixed costs — so break-even output INCREASES."}'::jsonb),
('5-4-break-even:tf:3cff9d80', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "The margin of safety is calculated by subtracting break-even sales from actual sales."}'::jsonb, '{"answer": true, "explain": "TRUE. Margin of safety = actual sales − break-even sales. It shows how far sales can fall before the business starts making a loss."}'::jsonb),
('5-4-break-even:tf:4d605968', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even analysis gives perfectly accurate predictions because it is based on mathematical calculations."}'::jsonb, '{"answer": false, "explain": "FALSE. Break-even uses estimated figures for future costs and revenues — it is a forecast, not a certainty. Actual results may differ due to competitors, price changes, or rising raw material costs."}'::jsonb),
('5-4-break-even:tf:0a79c038', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even analysis is most accurate for businesses that sell a wide variety of different products."}'::jsonb, '{"answer": false, "explain": "FALSE. Break-even is most straightforward for single-product businesses. Multi-product businesses have different costs and prices for each product, making break-even analysis complex and much less reliable."}'::jsonb),
('5-4-break-even:tf:29a51021', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "A break-even forecast can help a business secure a bank loan."}'::jsonb, '{"answer": true, "explain": "TRUE. Banks often ask to see a break-even forecast as part of a business plan. It demonstrates the owner has planned carefully and understood their finances, reassuring the bank that the loan is less risky."}'::jsonb),
('5-4-break-even:tf:6eaddf2b', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "On a break-even graph, the Total Revenue line starts at zero when output is zero."}'::jsonb, '{"answer": true, "explain": "TRUE. If a business sells zero units, it earns zero revenue. The Total Revenue line always begins at the origin (0, 0) and rises diagonally as units are sold."}'::jsonb),
('5-4-break-even:tf:6186c79e', '5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "On a break-even graph, the Fixed Costs line rises diagonally from left to right."}'::jsonb, '{"answer": false, "explain": "FALSE. The Fixed Costs line is horizontal — it stays flat at the same level regardless of output. It is the Total Costs and Total Revenue lines that are diagonal."}'::jsonb),
('5-4-break-even:learn:1052c3a8', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Break-even analysis is a financial tool that helps businesses calculate the minimum number of units they must sell to cover all costs — making neither a profit nor a loss.</p>\n    <ul>\n      <li><strong>Break-even quantity:</strong> The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss.</li>\n      <li><strong>Contribution per unit:</strong> Selling price minus variable cost per unit. Each unit sold \"contributes\" towards covering fixed costs before profit can be made.</li>\n      <li><strong>Total Revenue (TR):</strong> Selling price × quantity sold.</li>\n      <li><strong>Fixed Costs:</strong> Costs that do not change depending on output (e.g., rent, insurance, loan repayments).</li>\n      <li><strong>Variable Costs:</strong> Costs that change depending on the level of output (e.g., raw materials, packaging, direct labour).</li>\n      <li><strong>Total Costs:</strong> Total fixed costs + total variable costs.</li>\n      <li><strong>Margin of Safety:</strong> Actual sales − break-even sales. The amount by which a business''s actual output is greater than its break-even level of output.</li>\n      <li><strong>Break-even forecast:</strong> A prediction about the break-even quantity based on estimates of future sales revenues and costs.</li>\n      <li><strong>Profit:</strong> Total revenue − total costs (when TR > TC).</li>\n      <li><strong>Loss:</strong> When total costs exceed total revenue (TC > TR) — this occurs when output is below the break-even point.</li>\n    </ul>", "question": "According to the key definitions, what is ''contribution per unit''?", "options": ["Selling price minus variable cost per unit", "Selling price minus total fixed costs of the business", "Total revenue minus total costs of the business", "Fixed costs divided by the total quantity sold"]}'::jsonb, '{"answer": 0, "explain": "The card defines contribution per unit as selling price minus variable cost per unit — the amount each unit contributes towards covering fixed costs."}'::jsonb),
('5-4-break-even:learn:181aa6be', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Calculating the Break-Even Quantity", "reading": "<p>There is one formula you must know for the OCR GCSE exam. Break-even is <strong>always recorded in units</strong>, never in pounds (£).</p>\n    <div class=\"formula-box\">\n      <strong>Break-Even Output =</strong> Total Fixed Costs ÷ Contribution per Unit<br><br>\n      <strong>Contribution per Unit =</strong> Selling Price − Variable Cost per Unit\n    </div>\n    <p><strong>Worked Example:</strong> A toy manufacturer has fixed costs of £50,000, sells toys at £6 each, and variable costs of £2 per toy.</p>\n    <ul>\n      <li>Contribution = £6 − £2 = <strong>£4 per unit</strong></li>\n      <li>Break-even = £50,000 ÷ £4 = <strong>12,500 units</strong></li>\n    </ul>\n    <p><strong>⚠️ Key Rules:</strong></p>\n    <ul>\n      <li><strong>Always round UP</strong> if your answer is a decimal — you cannot break even on a fraction of a unit. For example, 583.3 rounds up to 584.</li>\n      <li><strong>Always show your working</strong> — even if the final answer is wrong, you can earn method marks for each correct step.</li>\n      <li><strong>Watch for time period traps</strong> — if costs are given weekly but the question asks for a daily break-even, divide fixed costs by 7 first.</li>\n    </ul>", "question": "According to this card, how should the break-even output always be recorded?", "options": ["In pounds, always rounded down if the answer is a decimal", "In units, always rounded up if the answer is a decimal", "In units, always rounded down if the answer is a decimal", "In pounds, always rounded up if the answer is a decimal"]}'::jsonb, '{"answer": 1, "explain": "The card states break-even is always recorded in units and rounded UP if the answer is a decimal, since a business cannot break even on a fraction of a unit."}'::jsonb),
('5-4-break-even:learn:56a5f32f', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "The Break-Even Graph", "reading": "<p>Break-even can be shown visually using a line graph. You may be asked to <strong>read and interpret</strong> a break-even graph in the exam.</p>\n    <ul>\n      <li><strong>Horizontal axis (x-axis):</strong> Output / Units sold</li>\n      <li><strong>Vertical axis (y-axis):</strong> Costs and Revenue (£)</li>\n      <li><strong>Fixed Costs line:</strong> A <em>horizontal</em> straight line — costs stay the same at all levels of output</li>\n      <li><strong>Total Costs line:</strong> Starts at the fixed cost level, then rises diagonally as output increases (adding variable costs)</li>\n      <li><strong>Total Revenue line:</strong> Starts at zero (no sales = no revenue), rises diagonally as output increases</li>\n      <li><strong>Break-even point:</strong> Where the Total Revenue line crosses the Total Costs line (TR = TC)</li>\n      <li><strong>Loss area:</strong> To the <em>left</em> of the break-even point — TC > TR, so the business makes a loss</li>\n      <li><strong>Profit area:</strong> To the <em>right</em> of the break-even point — TR > TC, so the business makes a profit</li>\n    </ul>\n    <p>The <strong>Margin of Safety</strong> is shown as the horizontal distance between actual output and the break-even point. A larger margin of safety means the business has more protection against a fall in sales.</p>", "question": "According to this card, what does the area to the left of the break-even point represent?", "options": ["The profit area, where total revenue exceeds total costs", "The margin of safety, showing spare capacity above the target", "The loss area, where total costs exceed total revenue", "The fixed cost area, where output has no effect on revenue"]}'::jsonb, '{"answer": 2, "explain": "The card explains the loss area lies to the left of the break-even point, where TC > TR; the profit area lies to the right, where TR > TC."}'::jsonb),
('5-4-break-even:learn:4b639d43', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Benefits of Break-Even Analysis", "reading": "<p>Break-even analysis is a powerful planning tool with several key benefits for businesses:</p>\n    <ul>\n      <li><strong>Planning sales targets:</strong> It shows exactly how many units must be sold to make a profit, giving the business a specific, measurable target to aim for.</li>\n      <li><strong>Securing a bank loan:</strong> Banks often ask to see a break-even forecast as part of a business plan. It demonstrates that the owner has planned carefully, reducing the risk for the bank and making them more willing to lend.</li>\n      <li><strong>Pricing and cost decisions:</strong> If the break-even output is too high to be realistic, the business can consider raising its price or cutting variable/fixed costs to lower the break-even point.</li>\n      <li><strong>Estimating expected profit:</strong> Once break-even is known, the business can forecast how much profit it would make at different levels of output.</li>\n      <li><strong>Assessing the margin of safety:</strong> The business can evaluate how far sales can fall before it starts making a loss, helping it plan for economic uncertainty.</li>\n    </ul>", "question": "According to this card, why might a bank be more willing to lend to a business?", "options": ["Break-even analysis guarantees that the business will always be profitable", "Break-even analysis removes the business''s need to ever repay any interest", "A break-even forecast proves the business will never face any real competitors at all", "A break-even forecast shows the owner has planned carefully, reducing the bank''s risk"]}'::jsonb, '{"answer": 3, "explain": "The card lists securing a bank loan as a benefit, since a break-even forecast demonstrates careful planning and reduces the perceived risk for the bank."}'::jsonb),
('5-4-break-even:learn:f6af63ff', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Limitations of Break-Even Analysis", "reading": "<p>Despite its usefulness, break-even analysis has several important limitations that businesses must be aware of:</p>\n    <ul>\n      <li><strong>It is only a prediction:</strong> All figures used are estimates of future costs and revenues. Actual results may differ significantly from the forecast.</li>\n      <li><strong>Competitors may change:</strong> If a new competitor enters the market, the business may have to lower its price to maintain sales. This reduces contribution per unit and raises the break-even output — making the original forecast inaccurate.</li>\n      <li><strong>Variable costs may change:</strong> If the cost of raw materials rises or falls unexpectedly, the variable cost per unit changes, altering the contribution and therefore the break-even point.</li>\n      <li><strong>Difficult for multi-product businesses:</strong> Calculating break-even is straightforward for a single-product business but becomes complex and less reliable when a firm sells many different products at different prices and costs.</li>\n      <li><strong>Promotional pricing is ignored:</strong> A business may offer discounts at launch, meaning actual revenue is less than the planned price — raising the real break-even output.</li>\n      <li><strong>Price increases may not raise revenue:</strong> If a price rise leads to a large fall in demand, total revenue could actually decrease — meaning the assumed revenue line on the graph would be inaccurate.</li>\n    </ul>", "question": "According to this card, why can a new competitor make a break-even forecast inaccurate?", "options": ["The business may have to lower its price, reducing contribution and raising break-even", "A new competitor automatically increases the business''s total fixed costs", "A new competitor always forces the business to stop selling its products internationally", "A new competitor guarantees that the business''s break-even output will fall"]}'::jsonb, '{"answer": 0, "explain": "The card explains a new competitor may force a price cut, reducing contribution per unit and raising the real break-even output above the original forecast."}'::jsonb),
('5-4-break-even:learn:56eb8162', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Advantages vs Disadvantages of Break-Even Analysis", "reading": "<div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Clear sales target:</strong> Shows exactly how many units must be sold to cover all costs and move into profit — giving management a specific goal to plan around.</div>\n    <div class=\"pro-item\"><strong>Supports bank loan applications:</strong> A bank manager is more likely to lend money if the business can present a break-even forecast as part of a well-prepared business plan.</div>\n    <div class=\"pro-item\"><strong>Informs pricing and cost decisions:</strong> If the break-even output is too high, the business knows it must either raise its price or reduce its costs to make profitability realistic.</div>\n    <div class=\"pro-item\"><strong>Forecasts profit at different outputs:</strong> Allows the business to estimate how much profit it could make at various sales levels, aiding strategic planning.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Based on estimates only:</strong> All revenue and cost figures are predictions. If prices or costs change unexpectedly, the entire forecast becomes inaccurate.</div>\n    <div class=\"con-item\"><strong>Ignores competition:</strong> New competitors entering the market may force price cuts, reducing contribution per unit and pushing the real break-even output above what was forecast.</div>\n    <div class=\"con-item\"><strong>Variable costs can change:</strong> Raw material price increases raise the variable cost per unit, shrinking the contribution and raising the break-even output beyond the original calculation.</div>\n    <div class=\"con-item\"><strong>Not suitable for multi-product businesses:</strong> Firms selling several products with different costs and prices find break-even analysis complex and unreliable as a guide to overall performance.</div>\n    </div>\n    </div>", "question": "According to this card, why is break-even analysis less reliable for multi-product businesses?", "options": ["Multi-product businesses are legally banned from using break-even analysis at all", "Calculating break-even becomes complex when products have different prices and costs", "Break-even analysis can only ever be calculated using a single fixed cost", "Multi-product businesses never have any variable costs to include at all"]}'::jsonb, '{"answer": 1, "explain": "The card lists multi-product businesses as a limitation, since calculating break-even is complex and less reliable when products have different prices and costs."}'::jsonb),
('5-4-break-even:learn:3d90d47c', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "How Changes Affect the Break-Even Point", "reading": "<p>A key exam skill is predicting what happens to the break-even output when variables change. Use the formula to reason through each scenario logically:</p>\n    <ul>\n      <li><strong>Selling price increases &rarr;</strong> Contribution per unit rises &rarr; Break-even output <strong>decreases</strong> (fewer units needed).</li>\n      <li><strong>Selling price decreases &rarr;</strong> Contribution per unit falls &rarr; Break-even output <strong>increases</strong> (more units needed).</li>\n      <li><strong>Fixed costs increase &rarr;</strong> More costs to cover &rarr; Break-even output <strong>increases</strong>.</li>\n      <li><strong>Fixed costs decrease &rarr;</strong> Fewer costs to cover &rarr; Break-even output <strong>decreases</strong>.</li>\n      <li><strong>Variable cost per unit increases &rarr;</strong> Contribution per unit falls &rarr; Break-even output <strong>increases</strong>.</li>\n      <li><strong>Variable cost per unit decreases &rarr;</strong> Contribution per unit rises &rarr; Break-even output <strong>decreases</strong>.</li>\n    </ul>\n    <p>On a break-even graph: a <strong>price increase</strong> is shown as a steeper Total Revenue line (pivoting upward). A <strong>rise in variable costs</strong> is shown as a steeper Total Costs line (pivoting upward from the fixed cost level).</p>", "question": "According to this card, what happens to the break-even output if fixed costs increase?", "options": ["It decreases, since higher fixed costs raise contribution per unit", "It stays exactly the same, since fixed costs do not affect break-even", "It increases, since more costs must be covered by contribution", "It decreases, since fewer units are then needed to cover costs"]}'::jsonb, '{"answer": 2, "explain": "The card explains that when fixed costs increase, there are more costs to cover, so the break-even output increases — the opposite happens when fixed costs fall."}'::jsonb),
('5-4-break-even:learn:d568b52f', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Lord Digby Jones & Hereford Furniture", "reading": "<div class=\"case-study-box\">\n    <h4>Case Study: Hereford Furniture</h4>\n    <p>Lord Digby Jones, a respected businessman, appeared on a BBC TV programme called <em>The New Trouble Shooter</em>. He visited Hereford Furniture, a family-owned business run by Mike Muxworthy and his daughter Kate. At the time of his visit, the business was making a loss of £80,000 and the jobs of 40 workers were at risk.</p>\n    <p>Lord Jones <strong>heavily criticised the owners for not completing break-even forecasts</strong>, calling them \"essential for good business planning.\" Without knowing their break-even output, the owners had no clear sales target and no way of knowing whether their pricing was sufficient to cover costs.</p>\n    <p><strong>The Takeaway:</strong> Even established businesses must regularly calculate break-even. Without it, managers are effectively \"flying blind\" — unable to make informed decisions about price, costs, or how much to produce. Lord Jones'' intervention helped the business develop a clear financial plan to return to profitability.</p>\n    </div>", "question": "According to the Hereford Furniture case study, what did Lord Digby Jones criticise the owners for?", "options": ["Charging their customers far too little for their furniture products", "Employing far too many staff relative to their level of output", "Refusing to apply for any external sources of finance at all", "Not completing break-even forecasts as part of their business planning"]}'::jsonb, '{"answer": 3, "explain": "The card explains Lord Jones criticised Hereford Furniture for not completing break-even forecasts, calling them essential for good business planning."}'::jsonb),
('5-4-break-even:learn:3956385b', '5-4-break-even', '5.4 Break-even', 'learn', 'mcq', 1, '{"readingTitle": "Case Study: Samantha Dixon — Cake Decorating", "reading": "<div class=\"case-study-box\">\n    <h4>Case Study: Samantha Dixon — Wedding Cake Business</h4>\n    <p>Samantha Dixon is starting up a cake decorating business. In her area there are already two other cake decorating businesses. She estimates she can sell wedding cakes at £300 each — slightly less than her competitors. Variable costs per cake are £180. Her fixed costs are £3,600 per year.</p>\n    <p><strong>Break-Even Calculation:</strong></p>\n    <ul>\n      <li>Contribution = £300 − £180 = £120 per cake</li>\n      <li>Break-even = £3,600 ÷ £120 = <strong>30 cakes per year</strong></li>\n    </ul>\n    <p><strong>What this means for Samantha:</strong></p>\n    <ul>\n      <li>She must sell at least 30 cakes before making any profit.</li>\n      <li>If she expects to sell 35 cakes, her margin of safety is 35 − 30 = 5 cakes.</li>\n      <li>She can show this forecast to a bank manager to support a loan application, demonstrating she has a clear financial plan.</li>\n    </ul>\n    <p><strong>Key Limitation:</strong> There are already 2 competitors. If they lower their prices below £300, Samantha may have to follow — reducing contribution per cake and pushing her break-even output above 30, making the forecast inaccurate.</p>\n    </div>", "question": "In the Samantha Dixon case study, what is her margin of safety if she sells 35 cakes?", "options": ["5 cakes, since her break-even output is 30 cakes per year", "35 cakes, since none of her cakes have covered any costs yet", "180 cakes, based on her variable cost per cake in pounds", "300 cakes, based on her selling price per cake in pounds"]}'::jsonb, '{"answer": 0, "explain": "The card calculates Samantha''s margin of safety as actual sales (35) minus break-even sales (30), giving a margin of safety of 5 cakes."}'::jsonb),
('5-4-break-even:misc:0a59752a', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write the break-even output in pounds, e.g. ''£12,500'' or ''£30''.</p><p><strong>✅ The correct idea:</strong> Break-even output must always be written in UNITS (e.g., ''12,500 units'' or ''30 cakes''). Writing a £ sign loses you a mark — the examiner is strict on this.</p>", "question": "In what unit must the break-even output always be recorded?", "options": ["In pounds, such as ''£12,500'' or ''£30''", "In units, such as ''12,500 units'' or ''30 cakes''", "In percentages, such as ''12,500%'' or ''30%''", "In hours, such as ''12,500 hours'' or ''30 hours''"]}'::jsonb, '{"answer": 1, "explain": "The card explains break-even output must always be written in units — writing a £ sign loses a mark, as examiners are strict on this."}'::jsonb),
('5-4-break-even:misc:eb45bcaf', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think ''break-even'' means the business is doing well or making a profit.</p><p><strong>✅ The correct idea:</strong> At break-even, the business makes NEITHER a profit NOR a loss. Total revenue exactly equals total costs — there is no money left over. It is the minimum acceptable level of sales.</p>", "question": "What does reaching the break-even point actually tell us about a business?", "options": ["It is making a healthy profit and performing very well overall", "It has definitely covered its costs and is now growing quickly", "It makes neither a profit nor a loss — revenue exactly equals total costs", "It has failed completely and will need to close down within the next year"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that break-even means doing well — at break-even, revenue exactly equals total costs and there is no money left over."}'::jsonb),
('5-4-break-even:misc:1b0abf9b', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students use total costs (not fixed costs) in the break-even formula: ''TC ÷ contribution''.</p><p><strong>✅ The correct idea:</strong> The formula uses FIXED COSTS only: FC ÷ contribution. Variable costs are already built into the contribution figure (price − VC), so using total costs would count variable costs twice.</p>", "question": "Which figure is used in the break-even formula: fixed costs or total costs?", "options": ["Total costs only, since fixed costs alone would understate the final answer", "Variable costs only, since fixed costs are irrelevant to break-even", "Total revenue only, since costs do not appear in the formula at all", "Fixed costs only, since variable costs are already built into contribution"]}'::jsonb, '{"answer": 3, "explain": "The card explains the formula uses fixed costs only, since variable costs are already accounted for within the contribution figure — using total costs would double-count them."}'::jsonb),
('5-4-break-even:misc:ab0f8899', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students round DOWN when the break-even gives a decimal (e.g., 583.3 becomes 583).</p><p><strong>✅ The correct idea:</strong> Always round UP. At 583 units the business has NOT yet covered all fixed costs — it needs to sell at least 584 to actually break even.</p>", "question": "How should a decimal break-even answer, such as 583.3, be rounded?", "options": ["Always rounded up, to 584, since 583 would not cover all fixed costs", "Always rounded down, to 583, to keep the final answer as low as possible", "Rounded to the nearest 10, to 580, for a simpler final answer", "Left as a decimal, since break-even units may include a fraction"]}'::jsonb, '{"answer": 0, "explain": "The card explains you must always round UP, since at 583 units the business has not yet covered all its fixed costs and would still be making a loss."}'::jsonb),
('5-4-break-even:misc:35e7e2d6', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students say break-even analysis is perfectly accurate and reliable because it uses maths.</p><p><strong>✅ The correct idea:</strong> Break-even is a PREDICTION based on estimated figures. Actual costs and revenues may differ significantly — competitors, price changes, or rising material costs can all make the forecast inaccurate.</p>", "question": "Why is break-even analysis not considered perfectly accurate and reliable?", "options": ["It uses maths, so the result is always guaranteed to be completely correct", "It is a prediction based on estimated figures that may turn out to be wrong", "It only ever uses figures that have already actually happened in the past", "It removes the need for a business to consider its competitors at all"]}'::jsonb, '{"answer": 1, "explain": "The card explains break-even is a prediction based on estimated figures — actual costs and revenues may differ significantly due to competitors or rising costs."}'::jsonb),
('5-4-break-even:misc:55d6bd21', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked to ''analyse a benefit of break-even'', students simply describe what break-even is.</p><p><strong>✅ The correct idea:</strong> The examiner wants U + APP + AN. State the benefit (U), apply it to the specific business in the case study (APP), and explain the impact on THAT business (AN). Describing the concept of break-even without any analysis or application scores zero.</p>", "question": "What must a full-mark ''analyse a benefit of break-even'' answer include, beyond a description?", "options": ["Only a general description of what break-even means as a concept", "A complete list of every possible benefit of break-even analysis", "Application to the specific business plus analysis of the impact on it", "A definition of profit rather than a definition of break-even itself"]}'::jsonb, '{"answer": 2, "explain": "The card explains the examiner wants U + APP + AN — describing the concept of break-even alone, without application or analysis, scores zero."}'::jsonb),
('5-4-break-even:misc:67bb625b', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students say ''it shows how many a business needs to sell to break-even'' as their Understanding mark.</p><p><strong>✅ The correct idea:</strong> This is tautological — you cannot explain break-even by using the term ''break-even''. You must show understanding by explaining WHAT break-even means: ''the point at which total revenue covers all costs, with no profit or loss.''</p>", "question": "Why does ''it shows how many a business needs to sell to break-even'' fail as an Understanding mark?", "options": ["It is factually incorrect and does not relate to break-even in any real way", "It only applies to businesses that sell more than one single product", "It is too detailed and includes far more information than is needed", "It is tautological, using the term ''break-even'' to explain break-even itself"]}'::jsonb, '{"answer": 3, "explain": "The card explains this answer is tautological — you cannot explain break-even using the word ''break-even''; you must state what it actually means."}'::jsonb),
('5-4-break-even:misc:f727141d', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked about a limitation, students say ''the figures might be wrong'' or ''it is inaccurate''.</p><p><strong>✅ The correct idea:</strong> This is too vague and scores zero marks. You must explain WHY the figures could be wrong — e.g., ''A new competitor could force the business to lower its price, reducing contribution per unit and raising the real break-even output above the forecast.''</p>", "question": "Why does ''the figures might be wrong'' fail as an answer about a limitation?", "options": ["It is too vague — you must explain WHY the figures could be wrong", "It is completely incorrect, since break-even figures are never wrong", "It only applies to businesses that use a graph, not a formula", "It correctly identifies the limitation without needing any more detail"]}'::jsonb, '{"answer": 0, "explain": "The card explains this answer is too vague and scores zero — you must explain why the figures could be wrong, e.g. a new competitor forcing a price cut."}'::jsonb),
('5-4-break-even:misc:4bddfdb9', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse ''margin of safety'' with ''profit''.</p><p><strong>✅ The correct idea:</strong> The margin of safety is measured in UNITS (actual sales minus break-even sales). It shows how far output can fall before a loss is made. Profit is a financial value in £ (TR minus TC) — a completely different calculation.</p>", "question": "What is the key difference between margin of safety and profit?", "options": ["Margin of safety and profit are simply two different names for the same figure", "Margin of safety is measured in units, while profit is a financial value in pounds", "Profit is measured in units, while margin of safety is a financial value in pounds", "Margin of safety can only be calculated once a business has already made a profit"]}'::jsonb, '{"answer": 1, "explain": "The card explains margin of safety (actual sales minus break-even sales) is measured in units, while profit (TR minus TC) is a financial value in pounds — a completely different calculation."}'::jsonb),
('5-4-break-even:misc:1888b62c', '5-4-break-even', '5.4 Break-even', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think any business can use break-even analysis equally well.</p><p><strong>✅ The correct idea:</strong> Break-even works best for businesses selling a SINGLE product at a fixed price. For businesses with multiple products at varying prices and costs, break-even is difficult to calculate accurately and much less useful as a planning tool.</p>", "question": "For which type of business does break-even analysis work best, according to this card?", "options": ["A business selling many different products at many different prices", "A business that has no fixed costs of any kind to consider", "A business selling a single product at one fixed price", "A business that has no variable costs of any kind to consider"]}'::jsonb, '{"answer": 2, "explain": "The card explains break-even works best for a single-product business at a fixed price; multi-product businesses with varying prices and costs find it far less useful."}'::jsonb),
('5-4-break-even:tips:57442409', '5-4-break-even', '5.4 Break-even', 'tips', 'mcq', 1, '{"readingTitle": "State / Identify — 1 mark — One Specific Point. One Sentence. Full Stop.", "reading": "\n          <p>A 1-mark question needs exactly <strong>one correct, specific point</strong>. Do not write a paragraph — one focused sentence is more than enough.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li>One clear, specific, relevant point = <strong>1 mark ✅</strong></li>\n            <li>A vague or general statement = <strong>0 marks ❌</strong></li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br>\n          <em>\"Break-even helps a business.\"</em><br>\n          Too vague — doesn''t say what the business can actually do with break-even information.</p>\n    \n          <p><strong>✅ Good Answer (1 mark):</strong><br>\n          <em>\"Break-even analysis allows Virgin Atlantic to identify the minimum number of passengers needed on each flight to cover all operating costs.\"</em><br>\n          Specific, relevant, and applied to the business context.</p>\n    \n          <p><strong>⚠️ Examiner Warning:</strong> Do NOT define break-even when the question asks for a USE of it. Re-read the exact wording of the question before writing your answer. A definition of \"what break-even is\" when asked \"how can break-even be used\" will score zero.</p>\n        ", "question": "What mistake does this card warn against when a question asks for a USE of break-even?", "options": ["Writing more than one clear, specific point in the answer that is given", "Applying the given answer to a specific business named in the case study text", "Rounding the final numerical answer up instead of rounding it down", "Writing a definition of break-even instead of describing how it is actually used"]}'::jsonb, '{"answer": 3, "explain": "The card warns that defining ''what break-even is'' when the question asks ''how can break-even be used'' scores zero — always re-read the exact question wording."}'::jsonb),
('5-4-break-even:tips:702fcdb3', '5-4-break-even', '5.4 Break-even', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Make Your Point, Then Explain the ''Why''", "reading": "\n          <p>A 2-mark question requires a <strong>point + explanation</strong>. State a fact, then immediately explain WHY or HOW it matters.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li><strong>Point (K — 1 mark):</strong> State the benefit, reason, or fact.</li>\n            <li><strong>Explanation (U — 1 mark):</strong> Explain why this matters or how it works.</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark max):</strong><br>\n          <em>\"Profit is important because it means the business has money.\"</em></p>\n    \n          <p><strong>✅ Good Answer (2 marks):</strong><br>\n          <em>\"Profit allows the business to invest in new equipment (K). This helps the business expand, replace worn-out assets, and remain competitive in its market in the long term (U).\"</em></p>\n    \n          <p><strong>⚠️ Examiner Warning — \"Survival\" Trap:</strong> Answers linking profit solely to survival were not awarded full marks in the exam. Survival is about cash flow, not profit. Focus on what profit <em>allows</em> the business to do: invest, expand, attract shareholders, repay debts, or develop new products.</p>\n        ", "question": "According to this card, why do answers linking profit solely to ''survival'' lose marks?", "options": ["Survival relates to cash flow, not profit, so the link is not fully accurate", "Survival is not a real business concept and should never be mentioned at all", "Profit and survival always mean exactly the same thing in any answer", "Survival can only be discussed in a 1-mark ''state'' question, not here"]}'::jsonb, '{"answer": 0, "explain": "The card explains survival is about cash flow, not profit — full marks require discussing what profit allows the business to do, such as invest or expand."}'::jsonb),
('5-4-break-even:tips:7d6cfe0f', '5-4-break-even', '5.4 Break-even', 'tips', 'mcq', 1, '{"readingTitle": "Calculate Break-Even — 3 marks — Always Show Every Step of Your Working", "reading": "\n          <p>Calculation questions are among the most predictable in the exam — but students still lose marks by not showing workings or forgetting to convert time periods.</p>\n    \n          <p><strong>The 3-Step Method:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Contribution:</strong> Selling price − variable cost per unit (1 mark)</li>\n            <li><strong>Step 2 — Divide:</strong> Fixed costs ÷ contribution, written clearly (1 mark)</li>\n            <li><strong>Step 3 — Final answer in UNITS:</strong> Write the number and the word \"units\" or the appropriate measure — never a £ sign (1 mark)</li>\n          </ul>\n    \n          <p><strong>⚠️ Watch for Multi-Step / Time Period Questions:</strong><br>\n          In the Sea View Hotel exam question, many students calculated the <em>weekly</em> break-even (105 rooms) instead of the <em>daily</em> break-even (15 rooms) — missing the final mark because they forgot to divide the weekly fixed costs by 7.<br>\n          <strong>Always re-read the question</strong> to check what time period is required.</p>\n    \n          <p><strong>⚠️ Add up ALL variable costs:</strong><br>\n          In the Luxury Cushions question, variable costs had three components (filling + cover + wage = £19 per unit). Students who missed one component got the wrong contribution and the wrong answer.</p>\n    \n          <p><strong>⚠️ Always round UP:</strong> If your answer is 583.3 → write 584. At 583 the business has not yet covered all its fixed costs.</p>\n        ", "question": "What error did many students make in the Sea View Hotel calculation question?", "options": ["They calculated the daily break-even instead of the required weekly figure", "They calculated the weekly break-even instead of the required daily figure", "They forgot to include the selling price anywhere in their calculation", "They forgot to round their final answer to the nearest whole number"]}'::jsonb, '{"answer": 1, "explain": "The card explains many students calculated the weekly break-even (105 rooms) instead of the required daily figure (15 rooms), missing a mark by not dividing by 7."}'::jsonb),
('5-4-break-even:tips:e8d1e94c', '5-4-break-even', '5.4 Break-even', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: Understanding → Application → Analysis", "reading": "\n          <p>The 3-mark analyse question is the most common written question on break-even. You <strong>must</strong> follow this exact structure to earn all 3 marks:</p>\n    \n          <ol>\n            <li><strong>Understanding (U) — 1 mark:</strong> State what the benefit/limitation IS. Explain the concept without using the term \"break-even\" tautologically.</li>\n            <li><strong>Application (APP) — 1 mark:</strong> Use a specific figure, name, or fact from the case study. Quote data from the text directly.</li>\n            <li><strong>Analysis (AN) — 1 mark:</strong> Explain the business-facing IMPACT. What does this mean FOR the business? Use language like \"this means that...\", \"as a result...\", \"this will lead to...\"</li>\n          </ol>\n    \n          <p><strong>Critical Rules:</strong></p>\n          <ul>\n            <li>You CANNOT score the Application mark without first scoring the Understanding mark.</li>\n            <li>Analysis must be <em>business-facing</em> — \"costs will increase\" alone is not enough. Say what the business must then DO as a result.</li>\n            <li>You cannot explain break-even by using the word \"break-even\": \"it helps GK know when it reaches break-even\" scores ZERO.</li>\n          </ul>\n    \n          <p><strong>Sentence Starters:</strong></p>\n          <ul>\n            <li><em>U: \"Break-even shows the point at which all costs are covered but no profit has yet been made...\"</em></li>\n            <li><em>APP: \"For [business name], this means that...\" / \"As the text states that [figure/fact]...\"</em></li>\n            <li><em>AN: \"As a result, the business will...\" / \"This means the business could...\" / \"This will lead to...\"</em></li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br>\n          <em>\"Break-even analysis helps GK know when it breaks even.\"</em></p>\n    \n          <p><strong>✅ Full-Mark Answer (3 marks):</strong><br>\n          <em>\"Break-even shows the point at which GK covers all of its costs but has not yet made a profit (U). GK''s break-even is 29 Deluxe kitchens per year (APP). This means the sales team can be set a target of selling more than 29 to move into profit, and GK can calculate its margin of safety to assess how resilient it is to falling consumer demand (AN).\"</em></p>\n        ", "question": "According to this card, what must happen before the Application mark can be awarded?", "options": ["The Analysis mark must already have been scored", "A conclusion must already have been written out", "The Understanding mark must be scored first", "A break-even graph must already have been drawn"]}'::jsonb, '{"answer": 2, "explain": "The card states you cannot score the Application mark without first scoring the Understanding mark — the U to APP to AN chain must be followed in order."}'::jsonb),
('5-4-break-even:tips:f3f933e5', '5-4-break-even', '5.4 Break-even', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two Impacts — 6 marks — Two Complete Chains of Analysis — No Conclusion Needed", "reading": "\n          <p>A 6-mark question is simply <strong>two 3-mark analyse questions written in sequence</strong>. You need two completely separate points, each with a full U → APP → AN chain.</p>\n    \n          <p><strong>Structure:</strong></p>\n          <ul>\n            <li><strong>Point 1:</strong> Understanding (1 mark) → Application (1 mark) → Analysis (1 mark)</li>\n            <li><strong>Point 2:</strong> Understanding (1 mark) → Application (1 mark) → Analysis (1 mark)</li>\n          </ul>\n    \n          <p><strong>⚠️ Do NOT write a conclusion</strong> — there are zero marks available for evaluation in a 6-mark question. Every sentence must earn marks for U, APP, or AN. A conclusion wastes time and earns nothing.</p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> Do not list every limitation you know. Write two limitations in full — with application and analysis each time. A long bullet-point list of vague statements scores very poorly.</p>\n    \n          <p><strong>✅ Example — \"Analyse two limitations of Samantha''s break-even forecast\":</strong></p>\n          <p><em><strong>Limitation 1:</strong> A new competitor could enter the market, increasing competition (U). There are already two other cake decorating businesses in Samantha''s area (APP). If they reduce their prices, Samantha may have to follow — cutting her contribution per cake and pushing her break-even output above 30 cakes, making the forecast inaccurate (AN).</em></p>\n          <p><em><strong>Limitation 2:</strong> The cost of ingredients could rise unexpectedly (U). Samantha''s variable cost is currently £180 per cake (APP). If ingredient costs increase, her contribution per cake falls, meaning she would need to sell more than 30 cakes to break even — making her existing forecast an underestimate (AN).</em></p>\n        ", "question": "According to this card, should a 6-mark ''analyse two impacts'' answer include a conclusion?", "options": ["Yes — a strong conclusion is worth one of the six marks available", "Yes — without a conclusion the answer cannot be marked at all", "No — but only because the question does not require two points", "No — there are zero marks for evaluation, so a conclusion wastes time"]}'::jsonb, '{"answer": 3, "explain": "The card warns against writing a conclusion in a 6-mark question, since there are zero evaluation marks available — every sentence should earn U, APP or AN marks instead."}'::jsonb),
