('5-4-break-even:match:b583b0f0', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Break-even quantity”?", "options": ["The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss.", "Selling price minus variable cost per unit — the amount each unit sold contributes towards covering fixed costs.", "Actual sales minus break-even sales — showing how far output can fall before the business starts making a loss.", "Selling price multiplied by quantity sold."]}'::jsonb, '{"answer": 0, "explain": "“Break-even quantity” means: The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss."}'::jsonb),
('5-4-break-even:match:ba9a1d5c', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Contribution per unit”?", "options": ["Selling price minus variable cost per unit — the amount each unit sold contributes towards covering fixed costs.", "Actual sales minus break-even sales — showing how far output can fall before the business starts making a loss.", "Selling price multiplied by quantity sold.", "Costs that do not change depending on the level of output, such as rent, insurance, and loan repayments."]}'::jsonb, '{"answer": 0, "explain": "“Contribution per unit” means: Selling price minus variable cost per unit — the amount each unit sold contributes towards covering fixed costs."}'::jsonb),
('5-4-break-even:match:f7d5ba52', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Margin of safety”?", "options": ["Actual sales minus break-even sales — showing how far output can fall before the business starts making a loss.", "Selling price multiplied by quantity sold.", "Costs that do not change depending on the level of output, such as rent, insurance, and loan repayments.", "Costs that change in line with the level of output, such as raw materials and packaging."]}'::jsonb, '{"answer": 0, "explain": "“Margin of safety” means: Actual sales minus break-even sales — showing how far output can fall before the business starts making a loss."}'::jsonb),
('5-4-break-even:match:c9a95cab', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total Revenue”?", "options": ["Costs that do not change depending on the level of output, such as rent, insurance, and loan repayments.", "Costs that change in line with the level of output, such as raw materials and packaging.", "Total fixed costs plus total variable costs at a given level of output.", "Selling price multiplied by quantity sold."]}'::jsonb, '{"answer": 3, "explain": "“Total Revenue” means: Selling price multiplied by quantity sold."}'::jsonb),
('5-4-break-even:match:bfdb9ea5', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fixed Costs”?", "options": ["Costs that change in line with the level of output, such as raw materials and packaging.", "Costs that do not change depending on the level of output, such as rent, insurance, and loan repayments.", "Total fixed costs plus total variable costs at a given level of output.", "A prediction of the break-even quantity based on estimated future sales revenues and costs."]}'::jsonb, '{"answer": 1, "explain": "“Fixed Costs” means: Costs that do not change depending on the level of output, such as rent, insurance, and loan repayments."}'::jsonb),
('5-4-break-even:match:ef22b70d', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Variable Costs”?", "options": ["Total fixed costs plus total variable costs at a given level of output.", "A prediction of the break-even quantity based on estimated future sales revenues and costs.", "The region to the right of the break-even point where total revenue exceeds total costs.", "Costs that change in line with the level of output, such as raw materials and packaging."]}'::jsonb, '{"answer": 3, "explain": "“Variable Costs” means: Costs that change in line with the level of output, such as raw materials and packaging."}'::jsonb),
('5-4-break-even:match:ea13467e', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total Costs”?", "options": ["A prediction of the break-even quantity based on estimated future sales revenues and costs.", "Total fixed costs plus total variable costs at a given level of output.", "The region to the right of the break-even point where total revenue exceeds total costs.", "The region to the left of the break-even point where total costs exceed total revenue."]}'::jsonb, '{"answer": 1, "explain": "“Total Costs” means: Total fixed costs plus total variable costs at a given level of output."}'::jsonb),
('5-4-break-even:match:15859300', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Break-even forecast”?", "options": ["A prediction of the break-even quantity based on estimated future sales revenues and costs.", "The region to the right of the break-even point where total revenue exceeds total costs.", "The region to the left of the break-even point where total costs exceed total revenue.", "Total fixed costs divided by contribution per unit (selling price minus variable cost per unit)."]}'::jsonb, '{"answer": 0, "explain": "“Break-even forecast” means: A prediction of the break-even quantity based on estimated future sales revenues and costs."}'::jsonb),
('5-4-break-even:match:6b6fb026', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profit area (on a break-even graph)”?", "options": ["The region to the left of the break-even point where total costs exceed total revenue.", "Total fixed costs divided by contribution per unit (selling price minus variable cost per unit).", "A horizontal straight line showing that fixed costs remain constant regardless of the level of output.", "The region to the right of the break-even point where total revenue exceeds total costs."]}'::jsonb, '{"answer": 3, "explain": "“Profit area (on a break-even graph)” means: The region to the right of the break-even point where total revenue exceeds total costs."}'::jsonb),
('5-4-break-even:match:e44f24cd', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Loss area (on a break-even graph)”?", "options": ["The region to the left of the break-even point where total costs exceed total revenue.", "Total fixed costs divided by contribution per unit (selling price minus variable cost per unit).", "A horizontal straight line showing that fixed costs remain constant regardless of the level of output.", "The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss."]}'::jsonb, '{"answer": 0, "explain": "“Loss area (on a break-even graph)” means: The region to the left of the break-even point where total costs exceed total revenue."}'::jsonb),
('5-4-break-even:match:7b519c3c', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Break-even formula”?", "options": ["A horizontal straight line showing that fixed costs remain constant regardless of the level of output.", "The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss.", "Selling price minus variable cost per unit — the amount each unit sold contributes towards covering fixed costs.", "Total fixed costs divided by contribution per unit (selling price minus variable cost per unit)."]}'::jsonb, '{"answer": 3, "explain": "“Break-even formula” means: Total fixed costs divided by contribution per unit (selling price minus variable cost per unit)."}'::jsonb),
('5-4-break-even:match:1ff305f7', '5-4-break-even', '5.4 Break-even', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fixed costs line (on a graph)”?", "options": ["The amount a business must sell to earn enough revenue to just cover its costs so that it does not make a profit or a loss.", "Selling price minus variable cost per unit — the amount each unit sold contributes towards covering fixed costs.", "A horizontal straight line showing that fixed costs remain constant regardless of the level of output.", "Actual sales minus break-even sales — showing how far output can fall before the business starts making a loss."]}'::jsonb, '{"answer": 2, "explain": "“Fixed costs line (on a graph)” means: A horizontal straight line showing that fixed costs remain constant regardless of the level of output."}'::jsonb),
('5-5-cash-and-cash-flow:exam:8fb27fff', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q2", "question": "These figures show that:", "options": ["An accounting error has been made because the firm is not profitable", "At least £49,000 must have been stolen from the firm''s bank account", "Despite being profitable, the firm may be unable to pay its short-term debts", "The firm is unlikely to experience cash shortages and is highly profitable"], "caseStudy": "The bank statement for an established firm shows that it ended 2023 close to its overdraft limit with an overdrawn balance of £5,000. The firm''s accounts show a profit of £44,000 for the year ending 31 December 2023.", "hint": "Think about the difference between cash and profit. Can you have one without the other?", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 1 mark (AO2)</h5><p><strong>Why C is correct:</strong> Profit (revenue − total costs = £44,000) and cash (the bank balance = −£5,000 overdrawn) are completely different. A business can be profitable overall but still have a negative bank balance — for example if it has made large investments or is waiting for customers to pay.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A</strong> — Wrong. Profit of £44,000 is genuine; there is no error. Cash and profit are different calculations.</li><li><strong>B</strong> — Wrong. There is absolutely no evidence of theft. The difference between profit and cash has many legitimate explanations.</li><li><strong>D</strong> — Wrong. The firm IS experiencing cash shortages right now (it is overdrawn); the high profit does not prevent this.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:d6b6efcd', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Yoshi''s Sweet Shop''s opening balance for December is expected to be:", "options": ["£4,700", "£4,800", "£14,200", "£14,300"], "caseStudy": "An extract from Yoshi''s Sweet Shop''s cash flow forecast for November is shown below.<table class=\"case-table\"><caption>Yoshi''s Sweet Shop — November Extract</caption><tr><th></th><th>November £</th></tr><tr><td>Total inflow</td><td>28,000</td></tr><tr><td>Total outflow</td><td>18,500</td></tr><tr><td>Net cash flow</td><td>9,500</td></tr><tr><td>Opening balance</td><td>−4,700</td></tr></table>", "hint": "The opening balance for December = the closing balance for November. Use: Closing Balance = Opening Balance + Net Cash Flow.", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £4,800 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Closing Balance (November) = Opening Balance + Net Cash Flow = −£4,700 + £9,500 = <strong>£4,800</strong>. This closing balance becomes December''s opening balance.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — £4,700:</strong> This removes the negative sign from the opening balance but ignores the net cash flow entirely.</li><li><strong>C — £14,200:</strong> This adds £9,500 to £4,700, ignoring the negative opening balance sign.</li><li><strong>D — £14,300:</strong> A rounding or arithmetic error — always be precise with negative values.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:81e7f916', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q5", "question": "A cash flow forecast can help a business:", "options": ["Calculate net profit", "Identify changes in the market", "Predict liquidity problems", "Understand the concept of break-even"], "hint": "Think about what a cash flow forecast actually shows — money in vs money out. Which of these four things does that help a business do?", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Predict liquidity problems (1 mark)</h5><p><strong>Why C is correct:</strong> A cash flow forecast shows when more cash goes out than comes in. This allows the business to predict when it may struggle to pay its debts (a liquidity problem) and act in advance.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> A cash flow forecast does NOT calculate profit. Profit = Revenue − Total Costs, which is on the income statement, not the cash flow forecast.</li><li><strong>B:</strong> Identifying market changes requires market research and competitor analysis — not a cash flow forecast.</li><li><strong>D:</strong> Break-even analysis uses selling price and costs, not a cash flow forecast.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:f5e4d45e', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Marble & Sons'' opening balance for September is expected to be:", "options": ["−£9,900", "−£4,700", "£4,700", "£9,900"], "caseStudy": "An extract from Marble &amp; Sons'' cash flow forecast for September is shown below.<table class=\"case-table\"><caption>Marble &amp; Sons — September Extract</caption><tr><th></th><th>September</th></tr><tr><td>Net cash flow</td><td>−£2,600</td></tr><tr><td>Opening balance</td><td>?</td></tr><tr><td>Closing balance</td><td>−£7,300</td></tr></table>", "hint": "Rearrange: Closing Balance = Opening Balance + Net Cash Flow → Opening Balance = Closing Balance − Net Cash Flow. Be careful with negatives.", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — −£4,700 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Opening Balance = Closing Balance − Net Cash Flow = −£7,300 − (−£2,600) = −£7,300 + £2,600 = <strong>−£4,700</strong>.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — −£9,900:</strong> This adds both negative figures together (−7,300 + −2,600). When net cash flow is negative, it reduces the balance — so the opening balance must be less negative than the closing balance.</li><li><strong>C — £4,700:</strong> Correct absolute value but wrong sign — the balance is negative.</li><li><strong>D — £9,900:</strong> Adds the absolute values with the wrong sign.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:507937b5', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Pia''s Diner''s total inflow for July is expected to be:", "options": ["£7,000", "£9,300", "£11,200", "£11,600"], "caseStudy": "An extract from Pia''s Diner''s cash flow forecast for July is shown below.<table class=\"case-table\"><caption>Pia''s Diner — July Extract</caption><tr><th></th><th>July £</th></tr><tr><td>Total inflow</td><td>?</td></tr><tr><td>Total outflow</td><td>13,500</td></tr><tr><td>Net cash flow</td><td>−1,900</td></tr><tr><td>Opening balance</td><td>−2,300</td></tr><tr><td>Closing balance</td><td>−4,200</td></tr></table>", "hint": "Net Cash Flow = Total Inflow − Total Outflow. Rearrange to find Total Inflow = Net Cash Flow + Total Outflow.", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £11,600 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Total Inflow = Net Cash Flow + Total Outflow = −£1,900 + £13,500 = <strong>£11,600</strong>.</p><p><strong>Verification:</strong> Closing Balance = Opening Balance + Net Cash Flow = −£2,300 + (−£1,900) = −£4,200 ✓</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — £7,000:</strong> No clear logic — possibly a random guess.</li><li><strong>B — £9,300:</strong> Possibly calculated by subtracting net cash flow from opening balance.</li><li><strong>C — £11,200:</strong> Possibly calculated using the closing balance minus net cash flow incorrectly.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:71b56b57', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q12", "question": "What is Pete''s Pet Shop''s estimated total cash outflow for July?", "options": ["£3,900", "£6,295", "£7,505", "£9,295"], "caseStudy": "An extract from Pete''s Pet Shop''s cash flow forecast for July is shown below.<table class=\"case-table\"><caption>Pete''s Pet Shop — July Extract</caption><tr><th></th><th>July</th></tr><tr><td>Total cash inflow</td><td>£6,900</td></tr><tr><td>Total cash outflow</td><td>?</td></tr><tr><td>Net cash flow</td><td>−£605</td></tr><tr><td>Opening balance</td><td>£3,000</td></tr><tr><td>Closing balance</td><td>£2,395</td></tr></table>", "hint": "Net Cash Flow = Total Inflow − Total Outflow. Rearrange to find: Total Outflow = Total Inflow − Net Cash Flow.", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — £7,505 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Total Outflow = Total Inflow − Net Cash Flow = £6,900 − (−£605) = £6,900 + £605 = <strong>£7,505</strong>.</p><p><strong>Verification:</strong> Closing = Opening + Net = £3,000 + (−£605) = £2,395 ✓</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — £3,900:</strong> No logical basis.</li><li><strong>B — £6,295:</strong> Subtracts £605 from £6,900 without considering the sign, giving £6,295 instead of adding.</li><li><strong>D — £9,295:</strong> Adds £6,900 + £3,000 - £605, mixing up different rows incorrectly.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:b3962c85', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Which of the following problems would be classed as a ''liquidity problem''?", "options": ["A breakdown on the production line", "Being short of funds to pay suppliers", "Experiencing high levels of wastage during the production process", "Having insufficient financial information to make business decisions"], "caseStudy": "A manufacturer is experiencing a range of problems.", "hint": "Liquidity = ability to pay SHORT-TERM debts. Which option is about an immediate inability to pay a bill?", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Being short of funds to pay suppliers (1 mark)</h5><p><strong>Why B is correct:</strong> Liquidity is defined as the ability to pay short-term debts. Being unable to pay suppliers is a direct example of a liquidity problem — the business does not have enough cash available to meet an immediate payment obligation.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> A production line breakdown is an operational problem, not a financial one.</li><li><strong>C:</strong> High wastage is an efficiency and quality management issue — not directly a cash/liquidity problem.</li><li><strong>D:</strong> Lack of financial information is a management and planning issue, not a liquidity problem.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:22c73c23', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q14", "question": "A business will make a profit if it:", "options": ["Ends the year with a positive bank balance", "Exceeds its break-even quantity", "Has costs that are greater than its revenues", "Pays off all of its debts"], "hint": "Profit = Revenue − Total Costs. Which answer describes a situation where revenue is greater than costs?", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Exceeds its break-even quantity (1 mark)</h5><p><strong>Why B is correct:</strong> At break-even, revenue exactly equals total costs. If a business sells more than the break-even quantity, revenue exceeds total costs, which is the definition of profit.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> A positive bank balance shows liquidity (cash), not profitability. The money in the bank could have come from a loan.</li><li><strong>C:</strong> If costs are greater than revenues, the business is making a LOSS, not a profit.</li><li><strong>D:</strong> Paying off debts relates to solvency, not to whether revenue exceeds costs.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:c630fbd6', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q16", "question": "Which of the following statements must be true?", "options": ["The company has at least £16,000 in its bank account", "The company will have no difficulty paying its bills", "The company''s cash outflows were £16,000 more than its cash inflows", "The company''s revenue exceeded its costs"], "caseStudy": "A company has made a net profit of £16,000.", "hint": "Think about the definition of profit. Profit = Revenue − Costs. If profit is positive, what does that tell us about revenue vs costs?", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — The company''s revenue exceeded its costs (1 mark, AO2)</h5><p><strong>Why D is correct:</strong> Net profit = Revenue − Total Costs. If net profit is £16,000 (positive), then by definition revenue must have been greater than total costs.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A:</strong> The company might have spent or invested the profit money; profit and cash are different. The bank balance could be very low even with a good profit.</li><li><strong>B:</strong> A profitable business can still struggle to pay its bills if it has a cash flow problem (e.g. customers not paying on time).</li><li><strong>C:</strong> That would describe a net CASH OUTFLOW of £16,000 — meaning a cash deficit, not a profit. It is the complete opposite of what happened.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:285fe721', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q17", "question": "What is Millican Garage''s closing balance for September?", "options": ["−£2,130", "£320", "£2,130", "£12,040"], "caseStudy": "A cash flow forecast for Millican Garage is shown below.<table class=\"case-table\"><caption>Millican Garage — Cash Flow Forecast</caption><tr><th></th><th>July £</th><th>August £</th><th>September £</th></tr><tr><td>Revenue (Total Inflow)</td><td>13,055</td><td>12,200</td><td>12,945</td></tr><tr><td>Car parts</td><td>4,200</td><td>4,240</td><td>3,900</td></tr><tr><td>Wages</td><td>3,100</td><td>3,250</td><td>4,450</td></tr><tr><td>Overheads</td><td>5,500</td><td>5,500</td><td>5,500</td></tr><tr><td><strong>Total outflow</strong></td><td><strong>12,800</strong></td><td><strong>12,990</strong></td><td><strong>13,850</strong></td></tr><tr><td><strong>Net cash flow</strong></td><td><strong>255</strong></td><td><strong>−790</strong></td><td><strong>−905</strong></td></tr><tr><td>Opening balance</td><td>1,760</td><td>2,015</td><td>1,225</td></tr><tr><td>Closing balance</td><td>2,015</td><td>1,225</td><td>?</td></tr></table>", "hint": "Closing Balance = Opening Balance + Net Cash Flow. Use September''s opening balance and net cash flow.", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £320 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Closing Balance = Opening Balance + Net Cash Flow = £1,225 + (−£905) = <strong>£320</strong>.</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — −£2,130:</strong> Adds −£905 and −£1,225 incorrectly (opening balance is +£1,225, not negative).</li><li><strong>C — £2,130:</strong> Adds 1,225 + 905 (ignores the negative sign on net cash flow).</li><li><strong>D — £12,040:</strong> Adds total inflow and opening balance, ignoring outflows — not a valid formula.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:exam:4543bc01', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'exam', 'mcq', 1, '{"num": "Q18", "question": "Pasha''s Carpets'' net cash flow for August 2019 is expected to be:", "options": ["−£3,700", "−£1,500", "£1,500", "£3,700"], "caseStudy": "An extract from Pasha''s Carpets'' cash flow forecast for August 2019 is shown below.<table class=\"case-table\"><caption>Pasha''s Carpets — August 2019 Extract</caption><tr><th></th><th>August £</th></tr><tr><td>Total inflow</td><td>44,000</td></tr><tr><td>Total outflow</td><td>45,500</td></tr><tr><td>Net cash flow</td><td>?</td></tr><tr><td>Opening balance</td><td>−1,100</td></tr><tr><td>Closing balance</td><td>−2,600</td></tr></table>", "hint": "Net Cash Flow = Total Inflow − Total Outflow. Both figures are given.", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — −£1,500 (1 mark, AO2)</h5><p><strong>Calculation:</strong> Net Cash Flow = £44,000 − £45,500 = <strong>−£1,500</strong>.</p><p><strong>Verification:</strong> Closing = Opening + Net = −£1,100 + (−£1,500) = −£2,600 ✓</p><p><strong>Why others are wrong:</strong></p><ul><li><strong>A — −£3,700:</strong> Possibly adds the opening balance to the outflow difference. Examiner noted many candidates chose C or A by recognising the inflow/outflow difference but failing to apply the correct sign.</li><li><strong>C — £1,500:</strong> Correct absolute value but the sign is wrong — outflow exceeded inflow so net cash flow must be negative.</li><li><strong>D — £3,700:</strong> No clear basis — possibly adds the two figures.</li></ul><p><strong>Examiner''s Comment:</strong> Candidates who got this wrong often recognised the difference between inflow and outflow, but did not see that it was a negative amount, therefore choosing C instead of B.</p></div>", "modelAnswer": ""}'::jsonb),
('5-5-cash-and-cash-flow:mcq:06307b61', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "A business has a net profit of £44,000 for the year but is £5,000 overdrawn at the bank. What does this tell us?", "options": ["An accounting error has been made because the business is not profitable", "At least £49,000 must have been stolen from the business", "Despite being profitable, the business may be unable to pay its short-term debts", "The business is highly profitable and unlikely to experience cash shortages"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. This illustrates the key difference between cash and profit. The business has made a profit (revenue exceeded costs) but has run out of cash — possibly because customers haven''t paid yet, or large investments were made. A = wrong because profit and cash are different; a business can have both. B = there is no evidence of theft. D = wrong because the overdraft shows it IS experiencing cash shortages right now."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:9aae47e8', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "Which of the following is the correct formula for net cash flow?", "options": ["Opening balance minus closing balance", "Total outflow minus total inflow", "Total inflow minus total outflow", "Closing balance minus opening balance"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. Net cash flow = Total Inflow − Total Outflow. A = that formula gives the change in balance, not net cash flow. B = this is the wrong way round and would give a negative when the business is doing well. D = closing minus opening gives the same result as net cash flow numerically, but the formula refers to inflows and outflows."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:d49f7e1f', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "A cash flow forecast is most useful for helping a business to:", "options": ["Calculate net profit for the year", "Identify changes in the market", "Predict liquidity problems before they occur", "Understand the concept of break-even"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. A cash flow forecast predicts when cash may run short — i.e. a potential liquidity problem — so the business can act in advance. A = a cash flow forecast does NOT show profit; that is done using the income statement. B = market analysis is a separate activity. D = break-even analysis uses costs and selling price, not a cash flow forecast."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:fadc2b81', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "A manufacturer is experiencing a range of problems. Which of the following would be classed as a ''liquidity problem''?", "options": ["A breakdown on the production line", "Being short of funds to pay suppliers", "Experiencing high levels of wastage during production", "Having insufficient financial information to make decisions"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Liquidity is the ability to pay short-term debts. Being unable to pay suppliers is a classic liquidity problem — not enough cash to meet immediate obligations. A = a production breakdown is an operational problem, not a financial one. C = wastage is an efficiency/quality problem. D = lack of information is a management/planning issue."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:22c73c23', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "A business will make a profit if it:", "options": ["Ends the year with a positive bank balance", "Exceeds its break-even quantity", "Has costs that are greater than its revenues", "Pays off all of its debts"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. At break-even, revenue exactly equals total costs. Selling more than the break-even quantity means revenue exceeds total costs — which is the definition of profit. A = a positive bank balance shows liquidity, not profitability (it could come from a loan). C = if costs exceed revenue, the business makes a LOSS, not a profit. D = paying off debts is about solvency, not profitability."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:add8b0ac', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "A company has made a net profit of £16,000. Which statement must be true?", "options": ["The company has at least £16,000 in its bank account", "The company will have no difficulty paying its bills", "The company''s cash outflows were £16,000 more than its cash inflows", "The company''s revenue exceeded its total costs"]}'::jsonb, '{"answer": 3, "explain": "Correct: D. Net profit = Revenue − Total Costs. If net profit is positive, revenue must have exceeded costs — that is what profit means. A = the business might have already spent or invested that profit money; cash and profit are separate. B = a profitable business can still have cash flow problems and struggle to pay bills. C = that would describe a net CASH OUTFLOW of £16,000, not profit — completely different concept."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:1e08e434', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "A cash flow shortage in a business is most often solved in the short term by arranging:", "options": ["An overdraft", "A long-term bank loan", "Crowdfunding", "Selling new shares"]}'::jsonb, '{"answer": 0, "explain": "Correct: A. An overdraft is specifically designed for short-term cash shortages — it gives the business immediate access to extra funds up to an agreed limit. B = a bank loan is a long-term source of finance, not suited to short-term cash gaps, and takes time to arrange. C = crowdfunding takes considerable time and effort to set up. D = selling shares is a long-term method of raising capital used by limited companies, not a quick fix for a cash shortage."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:1edc53c1', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "An extract from a cash flow forecast shows: Total Inflow £28,000 | Total Outflow £18,500 | Net Cash Flow £9,500 | Opening Balance −£4,700. What is the closing balance?", "options": ["£4,700", "£4,800", "£14,200", "£14,300"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Closing Balance = Opening Balance + Net Cash Flow = −£4,700 + £9,500 = £4,800. A = £4,700 is the opening balance with its sign removed — a common error. C = £14,200 would result from adding £9,500 to £4,700 (ignoring the negative sign). D = a rounding error — always be precise with negative opening balances."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:71316759', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "An extract shows: Net Cash Flow −£2,600 | Closing Balance −£7,300. What is the opening balance for this month?", "options": ["−£9,900", "−£4,700", "£4,700", "£9,900"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Rearranging: Opening Balance = Closing Balance − Net Cash Flow = −£7,300 − (−£2,600) = −£7,300 + £2,600 = −£4,700. A = −£9,900 results from adding both negative figures together. C = £4,700 ignores the negative sign. D = £9,900 adds the absolute values incorrectly."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:34424450', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "What is the difference between cash and profit?", "options": ["Cash and profit are the same thing — both measure how much money a business has made", "Cash is money available to pay immediate bills; profit is revenue minus total costs over a period", "Profit is the money in the bank; cash is calculated by subtracting costs from revenue", "Cash refers to money earned from sales; profit refers to money received from investors"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Cash is the money physically available (in bank accounts/on premises) to pay short-term debts right now. Profit is a calculated financial figure showing whether revenue exceeded costs over a period. A = confusing these two is the most common examiner-noted misconception at GCSE. C = has the definitions backwards. D = both definitions are incorrect."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:430e066e', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of a cash inflow for a retail business?", "options": ["Paying wages to shop staff", "Purchasing new stock from a supplier", "Revenue received from customers buying goods", "Paying the monthly rent on the shop premises"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. A cash inflow is money coming INTO the business. Revenue from customers is the main inflow for a retail business. A = paying wages is a cash OUTFLOW. B = purchasing stock is a cash OUTFLOW (money leaves the business to pay the supplier). D = paying rent is a cash OUTFLOW."}'::jsonb),
('5-5-cash-and-cash-flow:mcq:e029f80c', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'mcq', 'mcq', 1, '{"question": "A business has a closing balance of −£3,500 at the end of March. What does this tell us?", "options": ["The business has made a loss of £3,500 in March", "The business has spent £3,500 more than it earned in March", "The business has an overdraft situation — it owes its bank £3,500", "The business is definitely going to close down"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. A negative closing balance means the business has spent more than it has received in total, resulting in a deficit — effectively an overdrawn position at the bank. A = a negative closing balance is not the same as a loss; profit is calculated separately. B = the negative closing balance reflects the cumulative position, not just that one month''s activity. D = a single negative closing balance does not mean the business will close; it may be temporary and manageable."}'::jsonb),
('5-5-cash-and-cash-flow:tf:d96b206b', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "A negative net cash flow in one month always means the business is making a loss."}'::jsonb, '{"answer": false, "explain": "FALSE. Net cash flow and profit are completely different. A business can have a negative cash flow in one month (e.g. because it paid for a lot of stock in advance) while still being highly profitable overall. For example, HMJA Fashion had a negative cash flow in October when buying Christmas stock, but made a strong profit across the year."}'::jsonb),
('5-5-cash-and-cash-flow:tf:0b3a2436', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "The closing balance of one month becomes the opening balance of the next month."}'::jsonb, '{"answer": true, "explain": "TRUE. This is one of the key mechanics of a cash flow forecast. The cash remaining at the end of one period carries forward as the starting point for the next. This is why a large negative closing balance in one month immediately makes the following month more difficult."}'::jsonb),
('5-5-cash-and-cash-flow:tf:19ffbe86', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "A business that is profitable will always have enough cash to pay its bills on time."}'::jsonb, '{"answer": false, "explain": "FALSE. A business can be profitable on paper but still run out of cash — for example, if customers are slow to pay invoices, or if large expenses fall due before revenue arrives. This is called being ''cash poor but profit rich.'' This distinction is frequently tested in exams."}'::jsonb),
('5-5-cash-and-cash-flow:tf:73afb7a0', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "A cash flow forecast shows predicted future cash movements, not actual historical figures."}'::jsonb, '{"answer": true, "explain": "TRUE. A cash flow forecast is exactly that — a forecast, i.e. an estimate of what is expected to happen in the future. It is not the same as a bank statement (which shows actual past transactions). Because it is a prediction, it will not always be perfectly accurate."}'::jsonb),
('5-5-cash-and-cash-flow:tf:a57d5ebb', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "Net cash flow is calculated by subtracting total inflow from total outflow."}'::jsonb, '{"answer": false, "explain": "FALSE. The correct formula is Net Cash Flow = Total Inflow − Total Outflow (inflow minus outflow, not the other way around). Reversing the formula would give a negative number when the business is doing well, and a positive number when it is struggling — the complete opposite of what is correct."}'::jsonb),
('5-5-cash-and-cash-flow:tf:2f88796f', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "Cash includes only physical notes and coins held on the business premises."}'::jsonb, '{"answer": false, "explain": "FALSE. Cash is defined as money held in bank accounts as well as any notes and coins on the premises. In the modern business world, most cash is held electronically in bank accounts. A business could have thousands of pounds in ''cash'' without holding a single banknote."}'::jsonb),
('5-5-cash-and-cash-flow:tf:29f26a35', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "A business with a negative cash flow for several months in a row faces a serious risk of being forced to close."}'::jsonb, '{"answer": true, "explain": "TRUE. If negative cash flow continues over multiple months, the business may not be able to pay its suppliers, staff, or landlord. Creditors can apply to a court to force the business to sell its assets and close down. This can happen even to profitable businesses — as shown by the Deltic Group case study."}'::jsonb),
('5-5-cash-and-cash-flow:tf:f6195456', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "An overdraft is the most common short-term solution to a cash flow problem."}'::jsonb, '{"answer": true, "explain": "TRUE. An overdraft allows a business to spend beyond its bank balance up to an agreed limit. It is specifically designed for short-term shortfalls and can usually be arranged quickly with a bank. Interest is only charged on the amount overdrawn, making it efficient for temporary problems."}'::jsonb),
('5-5-cash-and-cash-flow:tf:60f0896a', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "A cash flow forecast can be useful when a business applies for a bank loan."}'::jsonb, '{"answer": true, "explain": "TRUE. Presenting a well-prepared cash flow forecast to a bank demonstrates that the business has carefully planned its financial future. It shows the bank that the business understands when money will come in and go out, and that it will be able to afford loan repayments."}'::jsonb),
('5-5-cash-and-cash-flow:tf:dac41571', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "Profit is simply the amount of money a business has in its bank account at any given time."}'::jsonb, '{"answer": false, "explain": "FALSE. The money in a bank account is cash — not profit. Profit is a calculated figure: Revenue − Total Costs, determined at the end of a trading period. A business might have £500 in the bank (cash) but have made £20,000 in profit over the year. These are completely different measurements."}'::jsonb),
('5-5-cash-and-cash-flow:tf:f263b989', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "Long-term cash flow forecasts are more reliable than short-term ones."}'::jsonb, '{"answer": false, "explain": "FALSE. It is the other way around. Short-term forecasts (e.g. for the next month or few months) are far more reliable because there is less time for unexpected changes to occur. The further ahead you forecast, the more uncertain the figures become — supplier prices may change, new competitors may arrive, or the economy may shift."}'::jsonb),
('5-5-cash-and-cash-flow:tf:3ddc41d6', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'tf', 'tf', 1, '{"question": "A positive net cash flow guarantees that a business is profitable."}'::jsonb, '{"answer": false, "explain": "FALSE. A positive net cash flow simply means more cash came in than went out that month. The business might have positive cash flow because it received a bank loan (an inflow) — but a loan is not profit. Profit requires revenue to exceed costs, which is a separate calculation. The two do not always move together."}'::jsonb),
('5-5-cash-and-cash-flow:learn:c257b866', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential definitions you <strong>must</strong> know for 5.5 Cash and Cash Flow.</p>\n<ul>\n<li><strong>Cash Flow Forecast:</strong> A statement showing the expected flow of money into and out of a business over a period of time.</li>\n<li><strong>Net Cash Flow:</strong> Total inflow minus total outflow for a given period.</li>\n<li><strong>Opening Balance:</strong> The amount of cash available at the beginning of the month — it is always the closing balance from the previous month.</li>\n<li><strong>Closing Balance:</strong> The amount of cash left at the end of the month. This becomes the opening balance for the next month.</li>\n<li><strong>Total Inflow:</strong> The total amount of cash flowing into a business in a given period.</li>\n<li><strong>Total Outflow:</strong> The total amount of cash flowing out of a business in a given period.</li>\n<li><strong>Positive Cash Flow:</strong> When more cash flows into the business than flows out during a month (also called a cash flow surplus).</li>\n<li><strong>Negative Cash Flow:</strong> When more cash flows out of the business than flows in during a month (also called a cash flow deficit).</li>\n<li><strong>Liquidity:</strong> The ability of a business to pay its short-term debts which must be paid in the near future.</li>\n<li><strong>Cash:</strong> Not simply notes and coins — also includes money held in a bank account.</li>\n<li><strong>Profit:</strong> The revenue received by a business minus the total costs of running that business.</li>\n<li><strong>Income / Revenue:</strong> Money that the business receives.</li>\n<li><strong>Expenditure:</strong> Money that the business pays out.</li>\n<li><strong>Short-term debts / expenses:</strong> Bills that a business has to pay in the near future, such as electricity, wages, or rent.</li>\n</ul>", "question": "According to the key definitions, what is the ''opening balance'' for a month?", "options": ["The closing balance carried over from the previous month", "The total inflow received during the current month alone", "The total outflow paid out during the current month", "The net cash flow calculated for the current month"]}'::jsonb, '{"answer": 0, "explain": "The card defines the opening balance as always being the closing balance from the previous month — it carries straight over rather than being freshly calculated."}'::jsonb),
('5-5-cash-and-cash-flow:learn:998dca4b', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'learn', 'mcq', 1, '{"readingTitle": "The Importance of Cash to a Business", "reading": "<p>A business needs cash to survive day-to-day, even if it is making a good profit. Cash is used to pay for <strong>short-term expenses and debts</strong> — the bills that arrive regularly and must be paid promptly.</p>\n<p>Examples of what cash is needed for include:</p>\n<ul>\n<li>Wages and salaries for staff</li>\n<li>Rent on premises</li>\n<li>Paying suppliers for stock and raw materials</li>\n<li>Heating, lighting and utility bills</li>\n</ul>\n<p>If these are not paid on time, the consequences can be severe: suppliers may stop delivering, staff may leave, landlords may evict the business, or creditors may force the business to close.</p>\n<h4>Liquidity</h4>\n<p><strong>Liquidity</strong> is the ability of a business to turn its assets into cash quickly enough to pay its short-term debts. A business with poor liquidity cannot pay its bills even if it owns valuable assets (such as machinery or property). A lack of liquidity is one of the main reasons businesses are forced to close — even profitable ones. Creditors (people owed money) can legally force the business to be sold so that debts are repaid from the proceeds.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: Broder Metals Group</h4>\n<p>Broder Metals Group supplies high-quality alloys to power stations, aircraft manufacturers, Formula 1 teams and oil exploration companies. They must order stock up to 12 months in advance. When events like the 2015 oil-price collapse reduced demand, Broder still had to pay wages, rent and suppliers — even though revenue had dropped significantly.</p>\n<p>To stay on top of this, Broder prepares annual budgets and monitors actual cash against the forecast every month. If a shortfall looks likely, they take action early: reducing prices to boost sales, or contacting the bank about available facilities. As their Finance Director states: \"Cash flow is fundamental — get it wrong and the company will fail.\"</p>\n<p><strong>Takeaway:</strong> Even a business selling to major industries can face a cash crisis if it fails to plan. Monitoring cash flow is not optional — it is fundamental to survival.</p>\n</div>", "question": "According to this card, what is ''liquidity''?", "options": ["The total profit a business has made over its last full financial year", "The ability of a business to turn assets into cash to pay short-term debts", "The total revenue a business receives from selling its products", "The amount of stock a business currently holds in its warehouse"]}'::jsonb, '{"answer": 1, "explain": "The card defines liquidity as a business''s ability to turn assets into cash quickly enough to pay short-term debts — poor liquidity can force even profitable businesses to close."}'::jsonb),
('5-5-cash-and-cash-flow:learn:cdd86e60', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'learn', 'mcq', 1, '{"readingTitle": "Cash vs Profit: A Critical Distinction", "reading": "<p>This is the most important distinction in this topic — and the one students most commonly confuse in the exam. Examiners consistently report that candidates lose marks by mixing these two concepts up.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">💰 Cash</div>\n<div class=\"pro-item\"><strong>What it is:</strong> Money held in bank accounts and on the premises, used to pay day-to-day expenses and short-term debts right now.</div>\n<div class=\"pro-item\"><strong>When it matters:</strong> Today — can you physically pay your bills this week?</div>\n<div class=\"pro-item\"><strong>Shown in:</strong> A cash flow forecast.</div>\n<div class=\"pro-item\"><strong>Formula:</strong> Cash = Opening Balance + Cash Received − Cash Paid</div>\n</div>\n<div>\n<div class=\"col-head\">📈 Profit</div>\n<div class=\"con-item\"><strong>What it is:</strong> Total revenue minus total costs. A calculated figure summarising whether the business has earned more than it spent over a period.</div>\n<div class=\"con-item\"><strong>When it matters:</strong> At the end of a trading period — did the business make money overall?</div>\n<div class=\"con-item\"><strong>Shown in:</strong> An income statement (profit and loss account).</div>\n<div class=\"con-item\"><strong>Formula:</strong> Profit = Revenue − Total Costs</div>\n</div>\n</div>\n<p><strong>Key insight:</strong> A business can be profitable but still run out of cash. For example, if a large customer owes the business £50,000 but hasn''t paid yet, the business has high revenue on paper but no cash to pay wages this week. This is sometimes called being \"cash poor but profit rich.\"</p>\n<p>Equally, a business can have lots of cash (e.g. from a bank loan) but still be making a loss.</p>\n<p><strong>Examiner warning:</strong> \"A business needs cash to survive\" is NOT the same as \"cash = profit.\" Never write that a cash flow forecast shows profit — it does not. The forecast only shows cash movements.</p>", "question": "According to this card, what is the key insight about cash and profit?", "options": ["A business can never be profitable if it also has plenty of cash", "Cash and profit are always exactly equal at the end of a trading period", "A business can be profitable on paper but still run out of cash", "A cash flow forecast shows the same information as a profit calculation"]}'::jsonb, '{"answer": 2, "explain": "The card''s key insight is that a business can be ''cash poor but profit rich'' — profitable on paper but unable to pay bills if customers haven''t paid yet."}'::jsonb),
('5-5-cash-and-cash-flow:learn:c9f2bf93', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'learn', 'mcq', 1, '{"readingTitle": "How to Read and Complete a Cash Flow Forecast", "reading": "<p>A cash flow forecast is a table showing predicted cash inflows and outflows over a number of months. Mastering the three formulas below will allow you to calculate any missing figure.</p>\n<div class=\"formula-box\">\n<strong>Net Cash Flow</strong> = Total Inflow − Total Outflow<br><br>\n<strong>Closing Balance</strong> = Opening Balance + Net Cash Flow<br><br>\n<strong>Opening Balance</strong> = Closing Balance of the previous month\n</div>\n<p>A worked example for HMJA Fashion (a business selling teenage clothes):</p>\n<table class=\"case-table\"><caption>Table 1 — HMJA Fashion Cash Flow Forecast</caption><tr><th></th><th>October £</th><th>November £</th><th>December £</th></tr><tr><td>Revenue (Total Inflow)</td><td>30,000</td><td>40,000</td><td>55,000</td></tr><tr><td>Wages</td><td>6,000</td><td>7,500</td><td>10,000</td></tr><tr><td>Overheads</td><td>3,500</td><td>3,500</td><td>4,000</td></tr><tr><td>Stock</td><td>35,000</td><td>15,000</td><td>10,000</td></tr><tr><td><strong>Total Outflow</strong></td><td><strong>44,500</strong></td><td><strong>26,000</strong></td><td><strong>24,000</strong></td></tr><tr><td><strong>Net Cash Flow</strong></td><td><strong>−14,500</strong></td><td><strong>14,000</strong></td><td><strong>31,000</strong></td></tr><tr><td>Opening Balance</td><td>1,000</td><td>−13,500</td><td>500</td></tr><tr><td><strong>Closing Balance</strong></td><td><strong>−13,500</strong></td><td><strong>500</strong></td><td><strong>31,500</strong></td></tr></table>\n<p><strong>October step-by-step:</strong> Net Cash Flow = £30,000 − £44,500 = <strong>−£14,500</strong>. Closing Balance = £1,000 + (−£14,500) = <strong>−£13,500</strong>. This negative closing balance carries forward as November''s opening balance.</p>\n<p>Notice: the negative October was planned — the business bought Christmas stock early. By December, cash has recovered strongly. A single negative month is not automatically a crisis.</p>", "question": "According to this card, why was HMJA Fashion''s negative October balance not automatically a crisis?", "options": ["The business had already closed down permanently by the end of October", "HMJA Fashion had no outflows at all recorded during that particular month of trading", "The negative balance was a permanent feature of every month of the year", "It was a planned outflow for buying Christmas stock early, and cash recovered later"]}'::jsonb, '{"answer": 3, "explain": "The card explains the negative October balance was planned (buying Christmas stock early), and cash recovered strongly by December — a single negative month is not automatically a crisis."}'::jsonb),
('5-5-cash-and-cash-flow:learn:f66d057d', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'learn', 'mcq', 1, '{"readingTitle": "The Usefulness of Cash Flow Forecasting", "reading": "<p>A cash flow forecast is one of the most important planning tools a business can use. Evaluating its usefulness is a very common exam question — especially at 7 marks.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits (Why it is useful)</div>\n<div class=\"pro-item\"><strong>1. Planning tool:</strong> The forecast can be shown to banks to help secure a loan or overdraft. It demonstrates the business has thought carefully about its financial future.</div>\n<div class=\"pro-item\"><strong>2. Anticipates cash shortages:</strong> By looking ahead, the business can see months where cash may run low — giving time to act before the problem becomes serious.</div>\n<div class=\"pro-item\"><strong>3. Enables remedies:</strong> Once a shortage is spotted in advance, solutions can be arranged — such as an overdraft, delaying purchases, or chasing unpaid invoices.</div>\n<div class=\"pro-item\"><strong>4. Provides targets:</strong> The forecast helps the business set spending targets to ensure there is always enough cash, and may identify a need to build up a cash surplus.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Limitations (Why it may not always be useful)</div>\n<div class=\"con-item\"><strong>Only an estimate:</strong> A forecast is a prediction — it cannot be 100% accurate. Circumstances can change unexpectedly.</div>\n<div class=\"con-item\"><strong>Supplier price changes:</strong> Unexpected cost increases (e.g. raw materials rising) make the outflow figures immediately inaccurate.</div>\n<div class=\"con-item\"><strong>External shocks:</strong> A pandemic, new competitor, or economic recession can make even well-researched forecasts unreliable very quickly.</div>\n<div class=\"con-item\"><strong>Short-term reliability only:</strong> Short-term forecasts (weeks/months ahead) are far more reliable than long-term ones (1+ years ahead).</div>\n</div>\n</div>", "question": "According to this card, why are short-term cash flow forecasts more reliable than long-term ones?", "options": ["Circumstances are less likely to change unexpectedly over a shorter period", "Short-term forecasts do not need to include any outflow figures at all", "Long-term forecasts are not allowed to be shown to a bank manager", "Short-term forecasts always show a bigger cash surplus than long-term ones"]}'::jsonb, '{"answer": 0, "explain": "The card lists short-term reliability as a limitation of forecasting in general — short-term forecasts (weeks/months) are far more reliable than long-term ones (1+ years) since less can change unexpectedly."}'::jsonb),
('5-5-cash-and-cash-flow:learn:3da62e48', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'learn', 'mcq', 1, '{"readingTitle": "Solving a Cash Flow Problem", "reading": "<p>When a business identifies a negative cash flow in its forecast, it has several options. The best solution depends on <strong>how long the shortage will last</strong>, <strong>how significant it is</strong>, and the specific situation of the business.</p>\n<ul>\n<li><strong>Arrange an overdraft:</strong> A short-term bank facility allowing spending beyond the balance. Quick to arrange but carries interest charges.</li>\n<li><strong>Reduce expenses:</strong> Cut non-essential costs to reduce outflows (e.g. delay new equipment purchases or reduce stock orders).</li>\n<li><strong>Raise prices:</strong> Higher prices increase inflows, though this risks losing customers to competitors.</li>\n<li><strong>Chase customers for payment:</strong> Send invoices promptly and reduce the credit period given to customers so money arrives faster.</li>\n<li><strong>Delay payment of bills:</strong> Negotiate with suppliers to pay later — this keeps cash in the business for longer without borrowing.</li>\n<li><strong>Cut stock levels:</strong> Ordering less stock reduces outflows and frees up cash tied up in unsold inventory.</li>\n<li><strong>Sell assets:</strong> Selling unused equipment or property raises a one-off cash inflow.</li>\n<li><strong>Seek additional finance:</strong> A bank loan or new investor/partner provides an immediate cash injection.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: The Deltic Group (2021)</h4>\n<p>The Deltic Group owned 53 nightclubs in the UK, valued at £80 million. During the Covid-19 pandemic, nightclubs were forced to close. With almost no revenue (only £80,000/month from a few bars), Deltic still faced £1 million per month in rent alone — plus utility bills, wages, and over £17 million in accumulated debt. Despite some government support, the cash flow problem became unsolvable. Unable to keep up with debts and with no certainty of when clubs could reopen, the owners were forced to sell the entire business to a Scandinavian company for just £10 million.</p>\n<p><strong>Takeaway:</strong> Even a large, established, and previously profitable business can be destroyed by a sustained cash flow problem. The business was not unprofitable by nature — it ran out of cash. This is why monitoring and planning cash flow is fundamental to business survival.</p>\n</div>", "question": "According to the Deltic Group case study, what ultimately happened to the business?", "options": ["It successfully expanded into new nightclub locations across the entire country", "It was forced to sell the entire business due to an unsolvable cash flow problem", "It received enough government support to fully cover all of its debts", "It made significant profits throughout the entire Covid-19 pandemic period"]}'::jsonb, '{"answer": 1, "explain": "The card explains Deltic''s cash flow problem became unsolvable during the pandemic, forcing owners to sell the business for far less than its previous value."}'::jsonb),
('5-5-cash-and-cash-flow:misc:a42eeb3d', '5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A cash flow forecast shows whether the business is making a profit or a loss.</p><p><strong>✅ The correct idea:</strong> A cash flow forecast only shows cash movements — money in and money out. It says nothing about profit. Profit is calculated on the income statement (revenue minus total costs). Examiners consistently note this is the most common error in this topic.</p>", "question": "What does a cash flow forecast actually show, according to this card?", "options": ["Whether the business is making a profit or a loss overall", "The total revenue and total costs for the entire trading year", "Only cash movements — money in and money out — not profit", "The break-even output the business needs to achieve each month"]}'::jsonb, '{"answer": 2, "explain": "The card explains a cash flow forecast only shows cash movements — profit is calculated separately on the income statement, not shown in a cash flow forecast."}'::jsonb)
